// Generated by GitHub Copilot
import { useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { FiBookOpen, FiTrendingDown } from 'react-icons/fi'
import PageHeader from '../../components/ui/PageHeader.jsx'
import Card, { CardBody, CardHeader } from '../../components/ui/Card.jsx'
import Select from '../../components/ui/Select.jsx'
import EmptyState from '../../components/ui/EmptyState.jsx'
import Breadcrumb from '../../components/layout/Breadcrumb.jsx'
import LoanSummaryCard from '../../components/cards/LoanSummaryCard.jsx'
import PaymentTimeline from '../../components/cards/PaymentTimeline.jsx'
import { useData } from '../../hooks/useData.js'
import { formatCurrency } from '../../utils/format.js'

/**
 * Loan passbook. Shows a loan summary, a repayment timeline and a remaining
 * balance card. A selector lets the admin switch between loans.
 */
export default function LoanPassbook() {
  const { loanId } = useParams()
  const navigate = useNavigate()
  const { loans } = useData()

  const [selected, setSelected] = useState(
    loanId || loans.find((l) => l.status === 'active')?.id || loans[0]?.id || '',
  )

  const loan = loans.find((l) => l.id === selected)

  const handleChange = (value) => {
    setSelected(value)
    navigate(`/admin/passbook/${value}`, { replace: true })
  }

  return (
    <div>
      <Breadcrumb items={[{ label: 'Loans', to: '/admin/loans' }, { label: 'Passbook' }]} />

      <PageHeader
        title="Loan Passbook"
        description="Detailed repayment record for a loan."
        action={
          <Select
            name="loan"
            value={selected}
            onChange={(e) => handleChange(e.target.value)}
            className="w-56"
            options={loans.map((l) => ({
              value: l.id,
              label: `${l.memberName} · ${formatCurrency(l.amount)}`,
            }))}
          />
        }
      />

      {!loan ? (
        <Card>
          <EmptyState
            icon={FiBookOpen}
            title="No loan selected"
            description="Choose a loan to view its passbook."
          />
        </Card>
      ) : (
        <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
          <div className="space-y-6 lg:col-span-1">
            <LoanSummaryCard loan={loan} />

            <Card className="p-5">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Remaining Balance</p>
                  <p className="mt-1 text-2xl font-bold text-amber-600">
                    {formatCurrency(loan.remaining)}
                  </p>
                </div>
                <span className="flex h-11 w-11 items-center justify-center rounded-lg bg-amber-50 text-amber-600">
                  <FiTrendingDown className="h-5 w-5" />
                </span>
              </div>
              <p className="mt-3 text-xs text-slate-400">
                {loan.status === 'closed'
                  ? 'This loan has been fully repaid.'
                  : `${formatCurrency(loan.amount - loan.remaining)} repaid of ${formatCurrency(loan.amount)}.`}
              </p>
            </Card>
          </div>

          <Card className="lg:col-span-2">
            <CardHeader
              title="Payment History"
              subtitle={`${loan.repayments.length} repayment${loan.repayments.length === 1 ? '' : 's'} recorded`}
            />
            <CardBody>
              <PaymentTimeline repayments={loan.repayments} />
            </CardBody>
          </Card>
        </div>
      )}
    </div>
  )
}
